def get_cves_by_severity(severity: str) -> list[dict]:
    return [c for c in CVE_DATABASE if c["severity"] == severity]

def get_cves_by_category(category: str) -> list[dict]:
    return [c for c in CVE_DATABASE if c["category"] == category]

def get_cve(cve_id: str) -> dict | None:
    return next((c for c in CVE_DATABASE if c["id"] == cve_id), None)

def get_categories() -> list[str]:
    seen: set[str] = set()
    return [c["category"] for c in CVE_DATABASE if not (c["category"] in seen or seen.add(c["category"]))]

def get_stats() -> dict:
    sev_count: dict[str, int] = {}
    for c in CVE_DATABASE:
        sev_count[c["severity"]] = sev_count.get(c["severity"], 0) + 1
    return {
        "total": len(CVE_DATABASE),
        "by_severity": sev_count,
        "categories": len(get_categories()),
    }
